function maxValue(events, k) {
  events.sort((a, b) => a[1] - b[1]);
  const n = events.length;
  const dp = Array.from({ length: n + 1 }, () => new Array(k + 1).fill(0));

  for (let i = 1; i <= n; i++) {
    let start = -1;
    for (let j = i - 1; j >= 1; j--) {
      if (events[j - 1][1] < events[i - 1][0]) {
        start = j;
        break;
      }
    }

    for (let j = 1; j <= k; j++) {
      if (start === -1) {
        dp[i][j] = Math.max(dp[i - 1][j], events[i - 1][2]);
      } else {
        dp[i][j] = Math.max(dp[i - 1][j], dp[start][j - 1] + events[i - 1][2]);
      }
    }
  }

  return dp[n][k];
}
```


    1. Sort the events based on their end day.
2. Initialize a 2D array dp to store the maximum sum of values for choosing a number of events.
3. Iterate through the sorted events, and for each event find the latest non-overlapping event.
4. Iterate through 1 to k, and for each count of events to attend, update the dp array using the latest non-overlapping event.
5. Return the maximum sum of values found in the dp array for attending k events.

